final:
module top_module(
    input rstn, clk, J, K,
    output reg obf_Q,
    output Qn
);always @ (posedge clk, negedge rstn)
    begin
        if (!rstn)
            obf_Q <= 1'b0;
        else
            case (obf_Q)
                1'b0 : obf_Q <= J;
                1'b1 : obf_Q <= ~K;
            endcase
    end

    assign Qn = ~obf_Q;
endmodule
